-- Table structure for content_articles
-- ----------------------------
DROP TABLE IF EXISTS `content_articles`;
CREATE TABLE `content_articles` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `created_at` datetime(3) DEFAULT NULL,
  `updated_at` datetime(3) DEFAULT NULL,
  `deleted_at` datetime(3) DEFAULT NULL,
  `author_id` bigint(20) unsigned DEFAULT NULL COMMENT '作者用户ID',
  `title` varchar(200) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT '标题',
  `slug` varchar(200) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT 'SEO友好链接slug',
  `summary` varchar(500) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT '摘要',
  `content` longtext COLLATE utf8_unicode_ci COMMENT '正文内容',
  `content_type` varchar(20) COLLATE utf8_unicode_ci DEFAULT 'markdown' COMMENT '内容类型 markdown/html',
  `cover_image` text COLLATE utf8_unicode_ci COMMENT '封面图(多图逗号分隔)',
  `seo_title` varchar(200) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT 'SEO标题',
  `seo_keywords` varchar(500) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT 'SEO关键词(逗号分隔)',
  `seo_description` varchar(500) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT 'SEO描述',
  `status` varchar(20) COLLATE utf8_unicode_ci DEFAULT 'draft' COMMENT '状态 draft/published/archived',
  `published_at` datetime(3) DEFAULT NULL COMMENT '发布时间',
  `view_count` bigint(20) unsigned DEFAULT NULL COMMENT '浏览量',
  `lead_count` bigint(20) unsigned DEFAULT NULL COMMENT '线索量(后续迭代)',
  `category_id` bigint(20) unsigned DEFAULT '0' COMMENT '分类ID',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_content_articles_slug` (`slug`),
  KEY `idx_content_articles_deleted_at` (`deleted_at`),
  KEY `idx_content_articles_author_id` (`author_id`),
  KEY `idx_content_articles_title` (`title`),
  KEY `idx_content_articles_status` (`status`),
  KEY `idx_content_articles_published_at` (`published_at`),
  KEY `idx_content_articles_category_id` (`category_id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

-- ----------------------------
-- Records of content_articles
-- ----------------------------

