INSERT INTO `sys_error` VALUES ('39', '2026-04-29 21:41:55.531', '2026-04-29 21:41:55.531', null, '后端', '登陆失败! 用户名不存在或者密码错误! | 错误: invalid connection \n 源文件:D:/golang/gin-vue-admin/server/api/v1/system/sys_user.go:68 \n 调用栈：github.com/flipped-aurora/gin-vue-admin/server/api/v1/system.(*BaseApi).Login\n	D:/golang/gin-vue-admin/server/api/v1/system/sys_user.go:68\ngithub.com/gin-gonic/gin.(*Context).Next\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/gin-gonic/gin.LoggerWithConfig.func1\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/logger.go:249\ngithub.com/gin-gonic/gin.(*Context).Next\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/flipped-aurora/gin-vue-admin/server/initialize.Routers.GinRecovery.func2\n	D:/golang/gin-vue-admin/server/middleware/error.go:78\ngithub.com/gin-gonic/gin.(*Context).Next\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/gin-gonic/gin.(*Engine).handleHTTPRequest\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/gin.go:633\ngithub.com/gin-gonic/gin.(*Engine).ServeHTTP\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/gin.go:589\nnet/http.serverHandler.ServeHTTP\n	D:/golang/exe/src/net/http/server.go:3210\nnet/http.(*conn).serve\n	D:/golang/exe/src/net/http/server.go:2092 \n 最终调用方法:D:/golang/gin-vue-admin/server/api/v1/system/sys_user.go:68 (Login lines 27-99)\n----- 产生日志的方法代码如下 -----\nfunc (b *BaseApi) Login(c *gin.Context) {\r\n	var l systemReq.Login\r\n	err := c.ShouldBindJSON(&l)\r\n	if err != nil {\r\n		response.FailWithMessage(err.Error(), c)\r\n		return\r\n	}\r\n	err = utils.Verify(l, utils.LoginVerify)\r\n	if err != nil {\r\n		response.FailWithMessage(err.Error(), c)\r\n		return\r\n	}\r\n\r\n	key := c.ClientIP()\r\n	// 判断验证码是否开启\r\n	openCaptcha := global.GVA_CONFIG.Captcha.OpenCaptcha               // 是否开启防爆次数\r\n	openCaptchaTimeOut := global.GVA_CONFIG.Captcha.OpenCaptchaTimeOut // 缓存超时时间\r\n	v, ok := global.BlackCache.Get(key)\r\n	if !ok {\r\n		global.BlackCache.Set(key, 1, time.Second*time.Duration(openCaptchaTimeOut))\r\n	}\r\n\r\n	var oc bool = openCaptcha == 0 || openCaptcha < interfaceToInt(v)\r\n	if oc && (l.Captcha == \"\" || l.CaptchaId == \"\" || !store.Verify(l.CaptchaId, l.Captcha, true)) {\r\n		// 验证码次数+1\r\n		global.BlackCache.Increment(key, 1)\r\n		response.FailWithMessage(\"验证码错误\", c)\r\n		// 记录登录失败日志\r\n		loginLogService.CreateLoginLog(system.SysLoginLog{\r\n			Username:     l.Username,\r\n			Ip:           c.ClientIP(),\r\n			Agent:        c.Request.UserAgent(),\r\n			Status:       false,\r\n			ErrorMessage: \"验证码错误\",\r\n		})\r\n		return\r\n	}\r\n\r\n	u := &system.SysUser{Username: l.Username, Password: l.Password}\r\n	user, err := userService.Login(u)\r\n	if err != nil {\r\n		global.GVA_LOG.Error(\"登陆失败! 用户名不存在或者密码错误!\", zap.Error(err))\r\n		// 验证码次数+1\r\n		global.BlackCache.Increment(key, 1)\r\n		response.FailWithMessage(\"用户名不存在或者密码错误\", c)\r\n		// 记录登录失败日志\r\n		loginLogService.CreateLoginLog(system.SysLoginLog{\r\n			Username:     l.Username,\r\n			Ip:           c.ClientIP(),\r\n			Agent:        c.Request.UserAgent(),\r\n			Status:       false,\r\n			ErrorMessage: \"用户名不存在或者密码错误\",\r\n		})\r\n		return\r\n	}\r\n	if user.Enable != 1 {\r\n		global.GVA_LOG.Error(\"登陆失败! 用户被禁止登录!\")\r\n		// 验证码次数+1\r\n		global.BlackCache.Increment(key, 1)\r\n		response.FailWithMessage(\"用户被禁止登录\", c)\r\n		// 记录登录失败日志\r\n		loginLogService.CreateLoginLog(system.SysLoginLog{\r\n			Username:     l.Username,\r\n			Ip:           c.ClientIP(),\r\n			Agent:        c.Request.UserAgent(),\r\n			Status:       false,\r\n			ErrorMessage: \"用户被禁止登录\",\r\n			UserID:       user.ID,\r\n		})\r\n		return\r\n	}\r\n	b.TokenNext(c, *user)\r\n}', 'error', null, '未处理');
