INSERT INTO `sys_error` VALUES ('137', '2026-05-10 13:47:01.943', '2026-05-10 13:47:01.943', null, '后端', 'register table failed | 错误: Error 1060 (42S21): Duplicate column name \'total\' \n 源文件:D:/golang/gin-vue-admin/server/initialize/gorm.go:77 \n 调用栈：github.com/flipped-aurora/gin-vue-admin/server/initialize.RegisterTables\n	D:/golang/gin-vue-admin/server/initialize/gorm.go:77\nmain.initializeSystem\n	D:/golang/gin-vue-admin/server/main.go:49\nmain.main\n	D:/golang/gin-vue-admin/server/main.go:32\nruntime.main\n	D:/golang/exe/src/runtime/proc.go:272 \n 最终调用方法:D:/golang/gin-vue-admin/server/initialize/gorm.go:77 (RegisterTables lines 37-88)\n----- 产生日志的方法代码如下 -----\nfunc RegisterTables() {\r\n	if global.GVA_CONFIG.System.DisableAutoMigrate {\r\n		global.GVA_LOG.Info(\"auto-migrate is disabled, skipping table registration\")\r\n		return\r\n	}\r\n\r\n	db := global.GVA_DB\r\n	err := db.AutoMigrate(\r\n\r\n		system.SysApi{},\r\n		system.SysIgnoreApi{},\r\n		system.SysUser{},\r\n		system.SysBaseMenu{},\r\n		system.JwtBlacklist{},\r\n		system.SysAuthority{},\r\n		system.SysDictionary{},\r\n		system.SysOperationRecord{},\r\n		system.SysAutoCodeHistory{},\r\n		system.SysDictionaryDetail{},\r\n		system.SysBaseMenuParameter{},\r\n		system.SysBaseMenuBtn{},\r\n		system.SysAuthorityBtn{},\r\n		system.SysAutoCodePackage{},\r\n		system.SysExportTemplate{},\r\n		system.Condition{},\r\n		system.JoinTemplate{},\r\n		system.SysParams{},\r\n		system.SysVersion{},\r\n		system.SysError{},\r\n		system.SysApiToken{},\r\n		system.SysLoginLog{},\r\n\r\n		example.ExaFile{},\r\n		example.ExaCustomer{},\r\n		example.ExaFileChunk{},\r\n		example.ExaFileUploadAndDownload{},\r\n		example.ExaAttachmentCategory{},\r\n		&content.SiteStats{},\r\n	)\r\n	if err != nil {\r\n		global.GVA_LOG.Error(\"register table failed\", zap.Error(err))\r\n		os.Exit(0)\r\n	}\r\n\r\n	err = bizModel()\r\n\r\n	if err != nil {\r\n		global.GVA_LOG.Error(\"register biz_table failed\", zap.Error(err))\r\n		os.Exit(0)\r\n	}\r\n	global.GVA_LOG.Info(\"register table success\")\r\n}', 'error', null, '未处理');
